function replayLogoAnimation(){var a=document.getElementById("logo-container");if(a&&a.parentNode){var b=a.cloneNode(!0);a.parentNode.replaceChild(b,a)}}window.addEventListener("pageshow",function(a){a.persisted&&setTimeout(replayLogoAnimation,0)});function newpage(){window.location=newLocation}$(".fade-out").click(function(a){a.preventDefault(),newLocation=this.href,$("body").fadeOut("slow",newpage)});